import{d as e,l as a}from"./chunks/theme.C9g6HaIV.js";import{c as r,Q as o,j as n,m as i}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"Billing","description":"","frontmatter":{},"headers":[],"relativePath":"guide/portal/billing.md","filePath":"guide/portal/billing.md","lastUpdated":1778912818000}'),s={name:"guide/portal/billing.md"};function d(l,t,c,h,u,g){return o(),n("div",null,[...t[0]||(t[0]=[i('<h1 id="billing" tabindex="-1">Billing <a class="header-anchor" href="#billing" aria-label="Permalink to &quot;Billing&quot;">​</a></h1><p>The <strong>Billing</strong> page in the Customer Portal gives you visibility into what you are using, what you have been billed, and what you have paid.</p><p>It is read-only — the Console does not currently accept self-service plan changes or in-portal payments. Coordinate with your account manager for plan changes or refunds.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>Four tabs: <strong>Usage</strong>, <strong>Invoices</strong>, <strong>Payments</strong>, <strong>Credits</strong>.</p><h2 id="usage-tab" tabindex="-1">Usage tab <a class="header-anchor" href="#usage-tab" aria-label="Permalink to &quot;Usage tab&quot;">​</a></h2><p><img src="'+e+'" alt="Portal Billing — Usage tab" class="light-only"><img src="'+a+'" alt="Portal Billing — Usage tab" class="dark-only"></p><p>The monthly consumption against your plan.</p><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Meter</strong></td><td>Internal key.</td></tr><tr><td><strong>Display Name</strong></td><td>Customer-facing label.</td></tr><tr><td><strong>Billed Value</strong></td><td>The count or amount applied for billing this period.</td></tr><tr><td><strong>Included Qty</strong></td><td>Your plan&#39;s entitlement.</td></tr><tr><td><strong>Usage %</strong></td><td>A progress bar showing billed-vs-included with the percentage.</td></tr><tr><td><strong>Period</strong></td><td>The billing period.</td></tr></tbody></table><p>The progress bar is colour-coded:</p><ul><li><strong>Red</strong> — at or above 90% of the entitlement.</li><li><strong>Yellow</strong> — at or above 75%.</li><li><strong>Neutral</strong> — below 75%.</li></ul><p>If a meter has no included quantity (unmetered service), it does not appear here.</p><h2 id="invoices-tab" tabindex="-1">Invoices tab <a class="header-anchor" href="#invoices-tab" aria-label="Permalink to &quot;Invoices tab&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Invoice #</strong></td><td>Reference.</td></tr><tr><td><strong>Period</strong></td><td>The billing period covered.</td></tr><tr><td><strong>Total</strong></td><td>Amount in your billing currency.</td></tr><tr><td><strong>Status</strong></td><td>Issued / Paid / Overdue / Void.</td></tr><tr><td><strong>Issued</strong></td><td>Date issued.</td></tr></tbody></table><h2 id="payments-tab" tabindex="-1">Payments tab <a class="header-anchor" href="#payments-tab" aria-label="Permalink to &quot;Payments tab&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Method</strong></td><td>Bank Transfer / Credit Card / Check / Wire / ACH / Other.</td></tr><tr><td><strong>Amount</strong></td><td></td></tr><tr><td><strong>Reference #</strong></td><td>Bank transaction ID, cheque number, etc.</td></tr><tr><td><strong>Processed</strong></td><td>Date the payment was reconciled.</td></tr></tbody></table><h2 id="credits-tab" tabindex="-1">Credits tab <a class="header-anchor" href="#credits-tab" aria-label="Permalink to &quot;Credits tab&quot;">​</a></h2><p>A placeholder for credit balance information. The message in the UI reads:</p><blockquote><p>Credit balance information is available on your account statement.</p></blockquote><p>For now, contact your account manager for credit balance details.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p>Requires the <code>view_billing</code> portal action.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Usage is updated periodically by the platform — figures shown are typically minutes-fresh, not real-time.</li><li>&quot;Billed Value&quot; already includes the production / non-production multipliers your contract specifies. If you want raw usage numbers, ask your account manager.</li><li>Voided invoices are not included in totals.</li></ul>',24)])])}const y=r(s,[["render",d]]);export{m as __pageData,y as default};
